    patch.aiCompanyContext = sf.aiCompanyContext;
  }

  if (typeof sf.aiServicesContext === 'string' && sf.aiServicesContext.trim() !== '') {
    patch.aiServicesContext = sf.aiServicesContext;
  }

  return patch;
})() }}

