return items.map(item => {
  const rawOutput = item.json.output;

  let parsed = null;
  let ok = false;
  let error = null;

  try {
    parsed = typeof rawOutput === 'string' ? JSON.parse(rawOutput) : rawOutput;

    // дополнительная проверка, что это именно объект JSON
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      ok = true;
    } else {
      parsed = null;
      error = 'Parsed value is not a JSON object';
    }
  } catch (e) {
    error = e.message;
  }

  return {
    json: {
      ok,
      rawOutput,
      error,

      lead_search_prompt: ok ? parsed.lead_search_prompt ?? null : null,
      outreach_message_template: ok ? parsed.outreach_message_template ?? null : null,
      search_filters: ok ? parsed.search_filters ?? null : null
    }
  };
});
